@Repository
public interface OrderRepository extends JpaRepository<Order, Long> {
    // Simple WHERE clause
    @Query("SELECT o FROM Order o WHERE o.status = :status")
    List<Order> findByStatus(@Param("status") String status);

    // JOIN query
    @Query("SELECT o FROM Order o JOIN o.user u WHERE u.email = :email")
    List<Order> findOrdersByUserEmail(@Param("email") String email);

    // Aggregate with GROUP BY
    @Query("SELECT o.status, COUNT(o) FROM Order o " +
           "GROUP BY o.status")
    List<Object[]> getOrderCountByStatus();

    // Subquery
    @Query("SELECT o FROM Order o WHERE o.user.id IN " +
           "(SELECT u.id FROM User u WHERE u.createdAt > :date)")
    List<Order> findRecentUserOrders(@Param("date") LocalDateTime date);

    // Native SQL with rowmapper
    @Query(value = "SELECT * FROM orders WHERE amount > ? " +
                   "AND created_at BETWEEN ? AND ?",
           nativeQuery = true)
    List<Order> findOrdersByAmountAndDateRange(
        BigDecimal minAmount, LocalDateTime start, LocalDateTime end);

    // Update query
    @Modifying
    @Transactional
    @Query("UPDATE Order o SET o.status = :newStatus " +
           "WHERE o.id = :id")
    int updateOrderStatus(@Param("id") Long id, @Param("newStatus") String status);

    // Delete query
    @Modifying
    @Transactional
    @Query("DELETE FROM Order o WHERE o.createdAt < :cutoffDate")
    int deleteOldOrders(@Param("cutoffDate") LocalDateTime cutoff);
}

// WRONG: loop exits on exception
List<Integer> numbers = Arrays.asList(1, 2, 0, 4, 5);
try {
    for (int num : numbers) {
        int result = 100 / num; // throws ArithmeticException when num=0
        System.out.println("Result: " + result);
    }
} catch (ArithmeticException e) {
    System.out.println("Caught: " + e);
}
// Output: Result: 100, Result: 50, Caught: ArithmeticException
// Loop exits, 4 and 5 are NOT processed

// CORRECT: process each item, skip on error
List<Integer> numbers = Arrays.asList(1, 2, 0, 4, 5);
for (int num : numbers) {
    try {
        int result = 100 / num;
        System.out.println("Result: " + result);
    } catch (ArithmeticException e) {
        System.out.println("Skipping " + num + ": " + e.getMessage());
    }
}
// Output: Result: 100, Result: 50, Skipping 0: / by zero, Result: 25, Result: 20

// CORRECT with finally
for (int num : numbers) {
    try {
        int result = 100 / num;
        System.out.println("Processed: " + num);
    } catch (Exception e) {
        System.out.println("Error: " + num);
    } finally {
        System.out.println("Cleanup for " + num);
    }
}

// Try-catch OUTSIDE loop: stops processing
List<String> items = Arrays.asList("10", "20", "invalid", "40");
int sum = 0;
try {
    for (String item : items) {
        sum += Integer.parseInt(item); // throws NumberFormatException on "invalid"
        System.out.println("Parsed: " + item);
    }
    System.out.println("Final sum: " + sum);
} catch (NumberFormatException e) {
    System.out.println("Parse error: " + e.getMessage());
}
// Output:
// Parsed: 10
// Parsed: 20
// Parse error: For input string: "invalid"
// Loop exits, "40" is NOT processed

// Try-catch INSIDE loop: continues processing
sum = 0;
for (String item : items) {
    try {
        sum += Integer.parseInt(item);
        System.out.println("Parsed: " + item);
    } catch (NumberFormatException e) {
        System.out.println("Skipped: " + item);
    }
}
System.out.println("Final sum: " + sum);
// Output:
// Parsed: 10
// Parsed: 20
// Skipped: invalid
// Parsed: 40
// Final sum: 70

