    @PostMapping
    public ResponseEntity<Order> createOrder(
        @RequestBody @Valid CreateOrderRequest request) {
        // request is deserialized from JSON body and validated
        Order order = orderService.create(request);
        return ResponseEntity.status(HttpStatus.CREATED).body(order);
    }

    // @RequestBody Optional for optional body
    @PostMapping("/batch")
    public ResponseEntity<List<Order>> createOrders(
        @RequestBody Optional<List<CreateOrderRequest>> requests) {
        if (requests.isEmpty()) {
            return ResponseEntity.badRequest().build();
        }
        List<Order> orders = requests.get().stream()
            .map(orderService::create)
            .collect(Collectors.toList());
        return ResponseEntity.status(HttpStatus.CREATED).body(orders);
    }
}

