// Diagnostic checklist
@RestController
@RequestMapping("/api/reports")
public class ReportController {
    @Autowired private MeterRegistry meterRegistry;
    @Autowired private ReportService service;

    @GetMapping("/slow-endpoint")
    public ResponseEntity<?> slowEndpoint() {
        long startTime = System.nanoTime();

        try {
            // Step 1: Enable SQL logging in application.properties
            // logging.level.org.hibernate.SQL=DEBUG
            // spring.jpa.properties.hibernate.format_sql=true

            // Step 2: Check memory and CPU
            MemoryMXBean memBean = ManagementFactory.getMemoryMXBean();
            MemoryUsage heapUsage = memBean.getHeapMemoryUsage();
            System.out.println("Heap used: " + heapUsage.getUsed() + " bytes");

            // Step 3: Profile this section
            long queryStart = System.nanoTime();
            var result = service.generateReport();
            long queryDuration = (System.nanoTime() - queryStart) / 1_000_000;

            meterRegistry.timer("report.generation.time")
                .record(queryDuration, TimeUnit.MILLISECONDS);

            return ResponseEntity.ok(result);
        } finally {
            long totalDuration = (System.nanoTime() - startTime) / 1_000_000;
            System.out.println("Total time: " + totalDuration + "ms");
        }
    }
}

