// BAD: without volatile, visibility issue
public class Counter {
    private long value = 0;  // not volatile

    public void increment() {
        value++;  // read-modify-write, not atomic
    }

    public long getValue() {
        return value;
    }
}

// BETTER: volatile for visibility of simple values
public class VolatileFlag {
    private volatile boolean running = true;

    public void stop() {
        running = false;  // writes to main memory
    }

    public void work() {
        while (running) {  // reads from main memory
            // do work
        }
    }
}

// BEST: use AtomicLong for atomic operations
public class AtomicCounter {
    private final AtomicLong value = new AtomicLong(0);

    public void increment() {
        value.incrementAndGet();  // atomic
    }

    public long getValue() {
        return value.get();
    }
}

// Example: Double-checked locking (WRONG without volatile)
public class Singleton {
    private static Singleton instance;  // BUG: visibility issue

    public static Singleton getInstance() {
        if (instance == null) {  // Thread A sees null
            synchronized (Singleton.class) {
                if (instance == null) {
                    instance = new Singleton();
                }
            }
        }
        return instance;  // Thread B might see partially initialized object
    }
}

// CORRECT: use volatile
public class SingletonFixed {
    private static volatile Singleton instance;  // volatile ensures visibility

    public static Singleton getInstance() {
        if (instance == null) {
            synchronized (Singleton.class) {
                if (instance == null) {
                    instance = new Singleton();
                }
            }
        }
        return instance;
    }
}

@Entity
public class User implements Serializable {
    private static final long serialVersionUID = 1L;

    private String email;

    // Sensitive data — excluded from serialization
    private transient String password;

    // Non-serializable field — must be transient
    private transient DateTimeFormatter formatter = DateTimeFormatter.ISO_DATE;

    // Computed field — can be recalculated after deserialization
    private transient int cachedAge;

    private LocalDate birthDate;

    // Restore transient fields after deserialization
    private void readObject(ObjectInputStream ois) 
            throws IOException, ClassNotFoundException {
        ois.defaultReadObject();

        // Restore transient fields
        formatter = DateTimeFormatter.ISO_DATE;
        recalculateAge();
    }

    private void recalculateAge() {
        cachedAge = Period.between(birthDate, LocalDate.now()).getYears();
    }
}

