// Immutable class example
public final class ImmutableUser {
    private final String email;
    private final int age;
    private final List<String> hobbies;  // mutable field

    public ImmutableUser(String email, int age, List<String> hobbies) {
        this.email = email;
        this.age = age;
        // Defensive copy to prevent external modification
        this.hobbies = new ArrayList<>(hobbies);
    }

    public String getEmail() {
        return email;
    }

    public int getAge() {
        return age;
    }

    public List<String> getHobbies() {
        // Return unmodifiable copy
        return Collections.unmodifiableList(hobbies);
    }

    // No setters!

    // Functional-style update returns new instance
    public ImmutableUser withAge(int newAge) {
        return new ImmutableUser(this.email, newAge, this.hobbies);
    }

    @Override
    public boolean equals(Object obj) {
        if (this == obj) return true;
        if (!(obj instanceof ImmutableUser)) return false;
        ImmutableUser other = (ImmutableUser) obj;
        return email.equals(other.email)
            && age == other.age
            && hobbies.equals(other.hobbies);
    }

    @Override
    public int hashCode() {
        return Objects.hash(email, age, hobbies);
    }
}

