// EntityManager usage
@Service
public class UserService {
    @Autowired
    private EntityManager em;

    @Transactional
    public void demo() {
        // CREATE: transient → managed
        User user = new User();
        user.setEmail("john@example.com");
        em.persist(user);  // insert on flush/commit
        // user is now Managed, in persistence context

        // READ: retrieves from DB or cache
        User found = em.find(User.class, 1L);
        // Same instance is returned if already managed

        // UPDATE: managed object is automatically tracked
        found.setEmail("john.new@example.com");
        em.flush();  // executes UPDATE SQL

        // DELETE: mark for removal
        em.remove(found);  // DELETE on flush/commit
    }

    @Transactional
    public void lazyLoadingIssue() {
        User user = em.find(User.class, 1L);
        em.flush();
        em.clear();  // Detach entity

        // user.getOrders() throws LazyInitializationException
        // orders were never loaded
    }

    @Transactional
    public void eagerLoad() {
        // Use JOIN FETCH to avoid N+1
        List<User> users = em.createQuery(
            "SELECT u FROM User u LEFT JOIN FETCH u.orders",
            User.class
        ).getResultList();
    }
}

